i18n.use(initReactI18next).init({
  compatibilityJSON: 'v4',
  lng: 'en',
  fallbackLng: 'en',
  resources: {en: {translation: en}, ru: {translation: ru}, he: {translation: he}},
  interpolation: {escapeValue: false},
});

export async function initializeAppLanguage(): Promise<void> {
  const saved = await AsyncStorage.getItem(LANGUAGE_KEY);
  const language: AppLanguage = saved === 'ru' || saved === 'he' ? saved : 'en';
  await i18n.changeLanguage(language);
  const shouldRTL = language === 'he';
  if (I18nManager.isRTL !== shouldRTL) {
    I18nManager.allowRTL(true);
    I18nManager.forceRTL(shouldRTL);
    DevSettings.reload();
  }
}

export async function changeAppLanguage(language: AppLanguage): Promise<void> {
  await AsyncStorage.setItem(LANGUAGE_KEY, language);
  await i18n.changeLanguage(language);
  const shouldRTL = language === 'he';
  if (I18nManager.isRTL !== shouldRTL) {
    I18nManager.allowRTL(true);
    I18nManager.forceRTL(shouldRTL);
    DevSettings.reload();
  }
}

export function localizedSiteName(site: string, t: (key: string) => string): string {
  const key: Record<string, string> = {'All Sites': 'common.allSites', 'Tower A': 'common.towerA', 'Skyline Tower': 'common.skylineTower', 'Harbor Point': 'common.harborPoint'};
  return key[site] ? t(key[site]) : site;
}

export default i18n;
